-- Generated from content/far-batch-004.csv by scripts/csv-to-seed-sql.mjs — do not edit by hand.
-- Idempotent: skips any question whose stem already exists.
with t as (
  select tp.id, tp.name, s.code from public.topics tp
  join public.subjects s on s.id = tp.subject_id
),
q(subject_code, topic, stem, a, b, c, d, correct_index, explanation, difficulty) as (values
  ('FAR', 'Liabilities & Provisions',
   'Gift certificates sold but not yet redeemed at the reporting date are reported as:',
   'Sales revenue of the period of sale', 'A contract liability until redeemed or until breakage is appropriately recognized', 'An appropriation of retained earnings', 'A contingent liability disclosed in the notes',
   1, 'Cash received for gift certificates creates an obligation to deliver goods — a contract liability under PFRS 15. Revenue is recognized on redemption, and expected breakage is recognized in proportion to the pattern of redemption.', 1),
  ('FAR', 'Liabilities & Provisions',
   'An entity offers one premium (costing P50) for every 10 product wrappers returned. It sold 100,000 products and expects 60% of wrappers to be redeemed. Wrappers actually redeemed during the year totaled 40,000. The estimated premium liability at year-end is:',
   'P100,000', 'P200,000', 'P300,000', 'P500,000',
   0, 'Expected redemptions = 100,000 × 60% = 60,000 wrappers = 6,000 premiums × P50 = P300,000 expense. Redeemed: 40,000 wrappers = 4,000 premiums × P50 = P200,000. Liability = P300,000 − P200,000 = P100,000.', 3),
  ('FAR', 'Liabilities & Provisions',
   'When bonds are issued between interest payment dates, the accrued interest collected from bondholders is:',
   'Recognized as interest income', 'Added to the carrying amount of the bonds', 'Credited to share premium', 'Credited to interest payable (or interest expense), to be offset against the first full interest payment',
   3, 'The issuer collects interest accrued since the last payment date because the first coupon pays a full period''s interest. The amount collected is a payable (or a credit to interest expense), not income or part of the bond''s issue price.', 2),
  ('FAR', 'Liabilities & Provisions',
   'Bonds with face value of P3,000,000 and unamortized discount of P120,000 were retired at 101. The retirement results in:',
   'A gain of P30,000', 'A loss of P30,000', 'A gain of P150,000', 'A loss of P150,000',
   3, 'Carrying amount = P3,000,000 − P120,000 = P2,880,000. Retirement price = P3,000,000 × 101% = P3,030,000. Loss = P3,030,000 − P2,880,000 = P150,000, recognized in profit or loss.', 2),
  ('FAR', 'Liabilities & Provisions',
   'Bonds with face value of P1,000,000 and a nominal rate of 8% payable annually were issued for P924,200 to yield 10%. Interest expense for the first year under the effective interest method is:',
   'P80,000', 'P92,420', 'P100,000', 'P107,580',
   1, 'Interest expense = carrying amount × effective rate = P924,200 × 10% = P92,420. Cash paid = P80,000; the P12,420 difference is discount amortization, raising the carrying amount to P936,620.', 2),
  ('FAR', 'Liabilities & Provisions',
   'An entity breached a long-term loan covenant on or before the reporting date, making the loan payable on demand. The loan is classified as noncurrent only if, on or before the reporting date:',
   'The entity expects to remedy the breach within six months', 'The entity has begun negotiations with the lender', 'The lender granted a grace period ending at least twelve months after the reporting date, within which the entity can rectify the breach', 'The lender has not yet demanded payment',
   2, 'Under PAS 1, the breach makes the liability current unless the lender agreed, by the reporting date, to a grace period of at least twelve months after the reporting date. A waiver obtained after the reporting date is a non-adjusting event.', 3),
  ('FAR', 'Liabilities & Provisions',
   'A currently maturing obligation that the entity refinanced on a long-term basis after the reporting date but before the financial statements were authorized for issue is classified as:',
   'A current liability', 'A noncurrent liability', 'Partly current and partly noncurrent', 'An off-balance-sheet item with note disclosure',
   0, 'Classification reflects rights existing at the reporting date. Refinancing completed after that date does not change the liability''s current classification; it is disclosed as a non-adjusting event.', 2),
  ('FAR', 'Liabilities & Provisions',
   'Which of the following costs is included in a restructuring provision under PAS 37?',
   'Costs of retraining the remaining staff', 'Marketing costs to rebuild the entity''s image', 'Costs of relocating continuing employees', 'Termination benefits for employees made redundant by the restructuring',
   3, 'A restructuring provision includes only direct expenditures necessarily entailed by the restructuring and not associated with ongoing activities. Retraining, relocation of continuing staff, and marketing relate to the future conduct of the business and are excluded.', 2),
  ('FAR', 'Liabilities & Provisions',
   'For an onerous contract, the provision is measured at:',
   'The total expected revenue under the contract', 'The lower of the cost of fulfilling the contract and the penalty or compensation from failing to fulfill it', 'The full remaining contract price', 'The unavoidable fixed overhead of the entity',
   1, 'The provision reflects the least net cost of exiting: the lower of the cost of fulfilling the contract and the cost (penalties or compensation) of failing to fulfill it. Any impairment of assets dedicated to the contract is recognized first.', 3),
  ('FAR', 'Liabilities & Provisions',
   'An entity has a recognized provision for a lawsuit and expects reimbursement from its insurer. The reimbursement is recognized:',
   'As a reduction of the provision', 'Only in the notes to the financial statements', 'As a separate asset when receipt is virtually certain, not exceeding the provision', 'As income when the claim is filed with the insurer',
   2, 'Reimbursements are recognized as a separate asset only when virtually certain, capped at the provision''s amount. In profit or loss, the expense may be presented net of the reimbursement; on the balance sheet, no offsetting of the asset and provision.', 2),
  ('FAR', 'Liabilities & Provisions',
   'A provision involving a large population of items (e.g., product warranties) is measured using:',
   'The expected value — probability-weighting all possible outcomes', 'The single most likely outcome only', 'The maximum possible outflow', 'The minimum amount of the range',
   0, 'For large populations, PAS 37 requires the expected value method, weighting each outcome by its probability. The individual most likely outcome is more relevant for a single obligation, adjusted for other possible outcomes.', 2),
  ('FAR', 'Liabilities & Provisions',
   'Under the cost model, a change in the estimated amount of a decommissioning (asset retirement) obligation due to revised cost estimates is:',
   'Recognized immediately in profit or loss', 'Recognized in other comprehensive income', 'Charged directly to retained earnings', 'Added to or deducted from the carrying amount of the related asset',
   3, 'Under IFRIC 1, changes in a decommissioning liability from revised estimates or discount rates adjust the related asset''s carrying amount under the cost model (subject to impairment and a floor of zero); periodic unwinding of the discount, in contrast, is a finance cost.', 3),
  ('FAR', 'Liabilities & Provisions',
   'An entity issued a P1,500,000 noninterest-bearing note payable due in three years for equipment (no cash price available). The market rate is 8% (PV factor of 1 at 8% for 3 periods = 0.7938). The note is initially recorded at:',
   'P1,190,700', 'P1,300,000', 'P1,388,890', 'P1,500,000',
   0, 'The note and the equipment are recorded at the note''s present value: P1,500,000 × 0.7938 = P1,190,700. The P309,300 discount is amortized to interest expense over three years using the effective interest method.', 2),
  ('FAR', 'Liabilities & Provisions',
   'Advances received from customers for goods to be delivered next year are reported as:',
   'Revenue of the current period', 'An offset against accounts receivable', 'A current liability until the goods are delivered', 'Deferred credits within equity',
   2, 'Customer advances create an obligation to perform — a contract liability, classified as current when delivery is expected within the normal operating cycle/twelve months. Revenue is recognized when control of the goods transfers.', 1),
  ('FAR', 'Liabilities & Provisions',
   'A contingent asset is recognized in the statement of financial position when:',
   'The inflow of benefits is probable', 'The realization of income is virtually certain, at which point it is no longer a contingent asset', 'Legal proceedings have commenced', 'Management is confident of a favorable outcome',
   1, 'Contingent assets are never recognized — they are disclosed when an inflow is probable. Once realization becomes virtually certain, the related asset is no longer contingent and recognition is appropriate.', 1),
  ('FAR', 'Liabilities & Provisions',
   'An entity paid salaries of P1,200,000 during the year. Accrued salaries payable were P100,000 at the beginning of the year and P150,000 at year-end. Salaries expense for the year is:',
   'P1,150,000', 'P1,200,000', 'P1,250,000', 'P1,350,000',
   2, 'Expense = cash paid − beginning accrual + ending accrual = P1,200,000 − P100,000 + P150,000 = P1,250,000. The P50,000 increase in the accrual represents expense incurred but not yet paid.', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'Past service cost arising from a plan amendment is recognized:',
   'Immediately in profit or loss at the earlier of when the amendment occurs and when related restructuring costs are recognized', 'In OCI over the average remaining service period', 'Only to the extent the benefits are already vested', 'As an adjustment to retained earnings',
   0, 'PAS 19 (revised) eliminated deferral of past service cost: the full amount — vested or not — is expensed immediately when the amendment or curtailment occurs (or when related restructuring costs are recognized, if earlier).', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'When a defined benefit plan is in surplus, the net defined benefit asset recognized is limited to:',
   'The fair value of plan assets', 'The full surplus in all cases', 'The asset ceiling — the present value of available refunds from the plan or reductions in future contributions', 'The accumulated remeasurement gains in OCI',
   2, 'A surplus is recognized only up to the asset ceiling: the present value of economic benefits available as refunds or reduced future contributions. The effect of the ceiling is a remeasurement recognized in OCI.', 3),
  ('FAR', 'Employee Benefits & Income Taxes',
   'Which of the following characterizes a defined contribution plan?',
   'The entity guarantees a specified retirement benefit based on final salary', 'The entity''s obligation is limited to the agreed contributions, with actuarial and investment risk falling on the employee', 'Actuarial assumptions are required to measure the entity''s obligation', 'Remeasurements are recognized in OCI',
   1, 'In a defined contribution plan, the entity''s legal or constructive obligation is limited to the amount it agrees to contribute; the employee bears the actuarial and investment risk. No actuarial valuation of the obligation is needed.', 1),
  ('FAR', 'Employee Benefits & Income Taxes',
   'An employee''s bonus is 10% of income after deducting the bonus but before deducting income tax. Income before bonus and tax is P4,400,000. The bonus is:',
   'P360,000', 'P400,000', 'P440,000', 'P484,000',
   1, 'B = 10% × (P4,400,000 − B); 1.1B = P440,000; B = P400,000. Check: income after bonus = P4,000,000 × 10% = P400,000.', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'Termination benefits are recognized as a liability and expense at the earlier of:',
   'When the employees are identified and when the plan is budgeted', 'When the offer is communicated and when employees render one more year of service', 'When the benefits are paid and when the employees leave', 'When the entity can no longer withdraw the offer of the benefits and when it recognizes related restructuring costs under PAS 37',
   3, 'Termination benefits arise from termination, not service, so they are recognized at the earlier of the date the entity can no longer withdraw the offer and the date it recognizes the costs of a related PAS 37 restructuring.', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'Plan assets of a defined benefit plan are measured at:',
   'Fair value', 'Amortized cost', 'Present value of expected contributions', 'Historical cost less impairment',
   0, 'Plan assets — qualifying insurance policies and assets held by the fund — are measured at fair value at each reporting date. They are netted against the present value of the defined benefit obligation to arrive at the net liability or asset.', 1),
  ('FAR', 'Employee Benefits & Income Taxes',
   'An entity reported pretax accounting income of P5,000,000, which included nondeductible expenses of P200,000, nontaxable income of P300,000, and was computed after book depreciation P500,000 lower than allowable tax depreciation. At a 25% tax rate, current tax expense is:',
   'P1,000,000', 'P1,100,000', 'P1,250,000', 'P1,475,000',
   1, 'Taxable income = P5,000,000 + P200,000 − P300,000 − P500,000 = P4,400,000; current tax = P4,400,000 × 25% = P1,100,000. The excess tax depreciation also creates a deferred tax liability of P125,000.', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'Which of the following differences does NOT give rise to deferred tax?',
   'Accrued warranty expense deductible only when paid', 'Excess of tax depreciation over book depreciation', 'Revenue collected in advance, taxable on receipt', 'Interest income on government securities that is exempt from income tax',
   3, 'Tax-exempt income is a permanent difference — it never enters taxable income, so there is no future tax consequence and no deferred tax. The other items are temporary differences that reverse in future periods.', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'When the enacted tax rate changes, existing deferred tax assets and liabilities are:',
   'Left at the amounts computed using the old rate until reversal', 'Adjusted prospectively as the differences reverse', 'Remeasured using the new rate, with the effect recognized in profit or loss except for items previously recognized outside profit or loss', 'Derecognized in full',
   2, 'PAS 12 measures deferred taxes at the rates expected to apply on reversal, based on enacted or substantively enacted rates. A rate change remeasures the balances immediately, with the effect following the original item (P/L, OCI, or equity).', 2),
  ('FAR', 'Employee Benefits & Income Taxes',
   'An entity may offset deferred tax assets against deferred tax liabilities only when:',
   'The amounts are expected to reverse in the same period', 'The entity intends to settle on a net basis', 'It has a legally enforceable right to offset current tax amounts and the deferred taxes relate to income taxes levied by the same taxation authority', 'The net amount is immaterial',
   2, 'Offsetting requires both a legally enforceable right of offset for current taxes and that the deferred taxes relate to taxes levied by the same authority on the same taxable entity (or entities intending to settle net).', 3),
  ('FAR', 'Shareholders'' Equity & Share-Based Payment',
   'An entity issued ordinary shares in exchange for a parcel of land. The transaction is best measured at:',
   'The par value of the shares issued', 'The fair value of the land received', 'The average market price of the shares over the past year', 'The carrying amount of the land in the seller''s books',
   1, 'Equity instruments issued for noncash consideration are measured by reference to the fair value of the goods received, unless that cannot be estimated reliably — in which case the fair value of the shares issued is used. Par value is a last resort.', 2),
  ('FAR', 'Shareholders'' Equity & Share-Based Payment',
